import { jsPDF } from "jspdf";

const FONT_BASE64 = "";

export function addVietnameseFont(doc: jsPDF) {
  try {
    const fontName = 'BeVietnamPro';
    const fileName = 'BeVietnamPro.ttf';

    doc.addFileToVFS(fileName, FONT_BASE64);
    doc.addFont(fileName, fontName, 'normal');

    return fontName;
  } catch (error) {
    console.error('Failed to load Vietnamese font:', error);
    return null;
  }
}
